// Time:  O(n!)
// Space: O(n^2)

class Solution {
public:
    int numSquarefulPerms(vector<int>& A) {
        unordered_map<int, int> count;
        for (const auto& a : A) {
            ++count[a];
        }
        unordered_map<int, unordered_set<int>> candidate;
        for (const auto& i : count) {
            for (const auto& j : count) {
                int x = i.first, y = j.first, s = sqrt(x + y);
                if (s * s == x + y) {
                    candidate[x].emplace(y);
                }
            }
        }

        int result = 0;
        for (const auto& i : count) {
            dfs(candidate, i.first, A.size() - 1, &count, &result);
        }
        return result;
    }

private:
    void dfs(const unordered_map<int, unordered_set<int>>& candidate,
             int x,
             int left,
             unordered_map<int, int> *count,
             int *result) {

        --(*count)[x];
        if (!left) {
            ++(*result);
        }
        if (candidate.count(x)) {
            for (const auto& y : candidate.at(x)) {
                if ((*count)[y] > 0) {
                    dfs(candidate, y, left - 1, count, result);
                }
            }
        }
        ++(*count)[x];
    }
};

# Time:  O(n!)
# Space: O(n^2)

import collections


class Solution(object):
    def numSquarefulPerms(self, A):
        """
        :type A: List[int]
        :rtype: int
        """
        def dfs(candidate, x, left, count, result):
            count[x] -= 1
            if left == 0:
                result[0] += 1
            for y in candidate[x]:
                if count[y]:
                    dfs(candidate, y, left-1, count, result)
            count[x] += 1

        count = collections.Counter(A)
        candidate = {i: {j for j in count if int((i+j)**0.5) ** 2 == i+j} 
                           for i in count}

        result = [0]
        for x in count:
            dfs(candidate, x, len(A)-1, count, result)
        return result[0]
